// Parse: /trigger notebooklm_asset <type> <notebook_id> [--flag=value ...] | <instructions>
// Supported types map 1:1 to the real notebooklm CLI subcommands.
const text = $input.first().json.message.text;
const body = text.replace('/trigger notebooklm_asset', '').trim();
const [head, ...rest] = body.split('|');
const instructions = rest.join('|').trim() || null;

const tokens = head.trim().split(/\s+/);
const [asset_type, notebook_id, ...flagTokens] = tokens;

const validTypes = ['audio', 'video', 'report', 'infographic', 'slide-deck'];
if (!validTypes.includes(asset_type)) {
  throw new Error(`Invalid asset_type '${asset_type}'. Use one of: ${validTypes.join(', ')}`);
}
if (!notebook_id) {
  throw new Error('notebook_id is required as second positional argument');
}

// Parse --key=value flags
const flags = {};
for (const tok of flagTokens) {
  const m = tok.match(/^--([a-z-]+)=(.+)$/);
  if (m) flags[m[1]] = m[2];
}

// Build the real CLI command
const parts = ['notebooklm', 'generate', asset_type, '-n', notebook_id, '--wait', '--json'];
for (const [k, v] of Object.entries(flags)) {
  parts.push(`--${k}`, v);
}
if (instructions) {
  // 'description' is the positional argument that maps to --instructions internally
  parts.push(JSON.stringify(instructions));
}

return [{ json: {
  chat_id: $input.first().json.message.chat.id,
  asset_type,
  notebook_id,
  flags,
  instructions,
  cli_command: parts.join(' '),
  consumer_agent: (asset_type === 'audio' || asset_type === 'video') ? 'Social-VideoCreator' : 'Social-ContentStrategy'
}}];

