// notebooklm CLI with --json --wait returns a JSON GenerationStatus on stdout.
// On failure, exitCode != 0 and stderr contains the message.
const exec = $input.first().json;
if (exec.exitCode !== 0) {
  throw new Error(`notebooklm CLI failed (exit ${exec.exitCode}): ${exec.stderr || 'unknown'}`);
}
let result;
try {
  result = JSON.parse(exec.stdout);
} catch (e) {
  throw new Error(`Failed to parse CLI JSON output: ${e.message}\nstdout: ${exec.stdout?.slice(0, 500)}`);
}

// Extract artifact metadata for delivery
return [{ json: {
  artifact_id: result.artifact_id || result.id,
  artifact_type: result.type || $('Parse — build real CLI command').item.json.asset_type,
  state: result.state || result.status,
  title: result.title || 'Untitled artifact',
  asset_url: result.url || result.download_url || null,
  notebook_id: $('Parse — build real CLI command').item.json.notebook_id,
  chat_id: $('Parse — build real CLI command').item.json.chat_id,
  raw: result
}}];

